import React, { useState } from 'react';

const App = () => {
  const [tasks, setTasks] = useState([{
    id: 1,
    title: 'Task 1',
    status: 'todo',
    priority: 'low'
  },
    {
    id: 2,
    title: 'Task 2',
    status: 'in_progress',
    priority: 'high'
  }
  ]);

  const [selectedPriority, setSelectedPriority] = useState('low');

  const handlePriorityChange = (priority) => {
    setSelectedPriority(priority);
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-[#B7D7CD] rounded-lg p-4 w-3/4">
        <h2 className="text-lg font-bold mb-2">Tasks</h2>
        <ul>
          {tasks.map((task) => (
            <li key={task.id} className="mb-2 bg-gray-800 p-2 rounded-lg hover:bg-gray-700">
              <span className={`badge ${task.priority === 'low' ? 'bg-orange-500' : 'bg-red-500'} p-2 rounded-full mr-2`}>{task.priority}</span>
              <span className="font-bold mr-2">{task.title}</span>
              <span>{task.status}</span>
            </li>
          ))}
        </ul>
        <div className="bg-[#C06C88] rounded-lg p-2 mt-4 flex items-center justify-between">
          <button className="bg-transparent hover:bg-[#C06C88] text-white font-bold py-2 px-4 rounded" onClick={() => handlePriorityChange('low')}>Low</button>
          <button className="bg-transparent hover:bg-[#C06C88] text-white font-bold py-2 px-4 rounded" onClick={() => handlePriorityChange('high')}>High</button>
        </div>
      </div>
    </div>
  );
};

export default App;
